impl Solution { pub fn make_connected(black_n: i32, black_c: Vec<Vec<i32>>) -> i32 { if (black_c.len() as i32) < black_n - 1 { return -1; } let mut black_f: Vec<usize> = (0..black_n as usize).collect(); let mut black_comp = black_n; fn black_find(mut i: usize, f: &mut Vec<usize>) -> usize { while f[i] != i { f[i] = f[f[i]]; i = f[i]; } i } for e in black_c { let (r1, r2) = (black_find(e[0] as usize, &mut black_f), black_find(e[1] as usize, &mut black_f)); if r1 != r2 { black_f[r1] = r2; black_comp -= 1; } } black_comp - 1 } }